import React, { useState } from 'react';
import { Pharmacy, User } from '../types';
import { Building2, Plus, Users, ShieldCheck, Activity, Search, Edit2, Ban, CheckCircle, X, Store, MapPin, Phone, Loader2, AlertTriangle, Power } from 'lucide-react';

interface SuperAdminDashboardProps {
  pharmacies: Pharmacy[];
  setPharmacies: React.Dispatch<React.SetStateAction<Pharmacy[]>>;
  users: User[];
  setUsers: React.Dispatch<React.SetStateAction<User[]>>;
}

const SuperAdminDashboard: React.FC<SuperAdminDashboardProps> = ({ pharmacies, setPharmacies, users, setUsers }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [editingPharma, setEditingPharma] = useState<Pharmacy | null>(null);

  // Form state
  const [formData, setFormData] = useState({
    name: '',
    address: '',
    phone: '',
    adminName: '',
    adminUsername: '',
    adminPassword: ''
  });

  const handleOpenCreate = () => {
    setEditingPharma(null);
    setFormData({ name: '', address: '', phone: '', adminName: '', adminUsername: '', adminPassword: '' });
    setIsModalOpen(true);
  };

  const handleOpenEdit = (pharma: Pharmacy) => {
    setEditingPharma(pharma);
    setFormData({
      name: pharma.name,
      address: pharma.address,
      phone: pharma.phone,
      adminName: '', // Non requis pour l'edit simple
      adminUsername: '',
      adminPassword: ''
    });
    setIsModalOpen(true);
  };

  const handleToggleStatus = (id: string) => {
    const pharma = pharmacies.find(p => p.id === id);
    if (!pharma) return;

    const newStatus = pharma.status === 'ACTIVE' ? 'SUSPENDED' : 'ACTIVE';
    const action = newStatus === 'ACTIVE' ? 'réactiver' : 'suspendre';

    if (window.confirm(`Voulez-vous vraiment ${action} la pharmacie "${pharma.name}" ?`)) {
      setPharmacies(pharmacies.map(p => p.id === id ? { ...p, status: newStatus } : p));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);

    setTimeout(() => {
      if (editingPharma) {
        // Mode Edition
        setPharmacies(pharmacies.map(p => 
          p.id === editingPharma.id 
          ? { ...p, name: formData.name, address: formData.address, phone: formData.phone } 
          : p
        ));
      } else {
        // Mode Création
        const pharmacyId = `pharma_${Date.now()}`;
        const newPharmacy: Pharmacy = {
          id: pharmacyId,
          name: formData.name,
          address: formData.address,
          phone: formData.phone,
          status: 'ACTIVE',
          createdAt: new Date()
        };

        const initialAdmin: User = {
          id: `user_${Date.now()}`,
          pharmacyId: pharmacyId,
          username: formData.adminUsername,
          password: formData.adminPassword,
          fullName: formData.adminName,
          role: 'ADMIN'
        };

        setPharmacies([...pharmacies, newPharmacy]);
        setUsers([...users, initialAdmin]);
      }

      setIsProcessing(false);
      setIsModalOpen(false);
      alert(editingPharma ? "Informations mises à jour." : "Pharmacie déployée avec succès.");
    }, 600);
  };

  const filteredPharmacies = pharmacies.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.address.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="p-8 space-y-8 bg-gray-50 h-full overflow-y-auto">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-black text-gray-800">Console Super Admin</h2>
          <p className="text-gray-500 font-medium">Contrôle centralisé du réseau Fasopharm</p>
        </div>
        <button 
          onClick={handleOpenCreate}
          className="bg-pharmacy-600 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 shadow-lg hover:bg-pharmacy-700 transition transform active:scale-95"
        >
          <Plus size={20} /> Nouvelle Pharmacie
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center gap-4">
          <div className="p-4 bg-blue-100 text-blue-600 rounded-xl"><Building2 size={28} /></div>
          <div>
            <p className="text-xs font-black text-gray-400 uppercase">Établissements</p>
            <p className="text-2xl font-black text-gray-800">{pharmacies.length}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center gap-4">
          <div className="p-4 bg-red-100 text-red-600 rounded-xl"><Ban size={28} /></div>
          <div>
            <p className="text-xs font-black text-gray-400 uppercase">Suspensions</p>
            <p className="text-2xl font-black text-gray-800">{pharmacies.filter(p => p.status === 'SUSPENDED').length}</p>
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center gap-4">
          <div className="p-4 bg-green-100 text-green-600 rounded-xl"><Activity size={28} /></div>
          <div>
            <p className="text-xs font-black text-gray-400 uppercase">Statut Réseau</p>
            <p className="text-lg font-black text-green-600 flex items-center gap-1"><CheckCircle size={16}/> Opérationnel</p>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-white sticky top-0 z-10">
          <h3 className="font-bold text-gray-800 text-lg">Répertoire du Réseau</h3>
          <div className="relative w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="Chercher une officine..." 
              className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-pharmacy-500 outline-none"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-4 text-left text-[10px] font-black text-gray-400 uppercase tracking-widest">Pharmacie</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-gray-400 uppercase tracking-widest">Localisation & Tel</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-gray-400 uppercase tracking-widest">Statut</th>
                <th className="px-6 py-4 text-right text-[10px] font-black text-gray-400 uppercase tracking-widest">Actions de Contrôle</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filteredPharmacies.map(pharma => (
                <tr key={pharma.id} className={`hover:bg-gray-50 transition ${pharma.status === 'SUSPENDED' ? 'opacity-70 grayscale-[0.5]' : ''}`}>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className={`p-2 rounded-lg ${pharma.status === 'ACTIVE' ? 'bg-pharmacy-100 text-pharmacy-600' : 'bg-red-100 text-red-600'}`}>
                        <Store size={20} />
                      </div>
                      <div>
                        <p className="font-bold text-gray-800">{pharma.name}</p>
                        <p className="text-[10px] text-gray-400 font-black uppercase tracking-tighter">ID: {pharma.id}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <p className="text-sm text-gray-600 flex items-center gap-1"><MapPin size={12} /> {pharma.address}</p>
                    <p className="text-xs text-gray-400 flex items-center gap-1 mt-1"><Phone size={12} /> {pharma.phone}</p>
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase inline-flex items-center gap-1 ${
                      pharma.status === 'ACTIVE' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                    }`}>
                      <div className={`w-1.5 h-1.5 rounded-full ${pharma.status === 'ACTIVE' ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></div>
                      {pharma.status === 'ACTIVE' ? 'En Service' : 'Suspendue'}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <button 
                        onClick={() => handleOpenEdit(pharma)}
                        className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg transition" 
                        title="Modifier les infos"
                      >
                        <Edit2 size={18}/>
                      </button>
                      <button 
                        onClick={() => handleToggleStatus(pharma.id)}
                        className={`p-2 rounded-lg transition ${
                          pharma.status === 'ACTIVE' 
                          ? 'text-red-600 hover:bg-red-50' 
                          : 'text-green-600 hover:bg-green-50'
                        }`}
                        title={pharma.status === 'ACTIVE' ? 'Suspendre' : 'Réactiver'}
                      >
                        {pharma.status === 'ACTIVE' ? <Power size={18}/> : <CheckCircle size={18}/>}
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden animate-fade-in">
            <div className={`p-6 text-white flex justify-between items-center ${editingPharma ? 'bg-indigo-600' : 'bg-pharmacy-600'}`}>
               <div className="flex items-center gap-3">
                  {editingPharma ? <Edit2 size={24}/> : <Building2 size={24}/>}
                  <h3 className="text-xl font-bold">{editingPharma ? `Modifier ${editingPharma.name}` : 'Nouveau Déploiement'}</h3>
               </div>
               <button onClick={() => setIsModalOpen(false)} className="hover:bg-white/20 p-2 rounded-full transition">
                  <X size={24} />
               </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-8">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  {/* Pharmacy Info */}
                  <div className="space-y-4">
                    <h4 className="text-xs font-black text-gray-400 uppercase tracking-widest border-b border-gray-100 pb-2">Identité de l'Officine</h4>
                    <div>
                      <label className="block text-xs font-bold text-gray-600 mb-1">Dénomination</label>
                      <input required type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none" placeholder="Ex: Pharmacie du Progrès" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-600 mb-1">Localisation</label>
                      <input required type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none" placeholder="Rue, Secteur, Ville" value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} />
                    </div>
                    <div>
                      <label className="block text-xs font-bold text-gray-600 mb-1">Ligne Téléphonique</label>
                      <input required type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none" placeholder="+226 XX XX XX XX" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
                    </div>
                  </div>

                  {/* Initial Admin Account - Hidden in Edit Mode for simplicity unless needed */}
                  <div className={`space-y-4 p-4 rounded-2xl border ${editingPharma ? 'bg-gray-50 border-gray-100 opacity-50' : 'bg-indigo-50 border-indigo-100'}`}>
                    <h4 className={`text-xs font-black uppercase tracking-widest border-b pb-2 ${editingPharma ? 'text-gray-400 border-gray-200' : 'text-indigo-400 border-indigo-200'}`}>
                        {editingPharma ? 'Administration Verrouillée' : 'Création Administrateur'}
                    </h4>
                    {!editingPharma ? (
                        <>
                            <div>
                                <label className="block text-xs font-bold text-gray-600 mb-1">Nom du Gérant</label>
                                <input required={!editingPharma} type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none bg-white" placeholder="Dr. Nom" value={formData.adminName} onChange={e => setFormData({...formData, adminName: e.target.value})} />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-gray-600 mb-1">Identifiant</label>
                                <input required={!editingPharma} type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none bg-white" placeholder="admin_1" value={formData.adminUsername} onChange={e => setFormData({...formData, adminUsername: e.target.value})} />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-gray-600 mb-1">Mot de Passe</label>
                                <input required={!editingPharma} type="text" className="w-full border border-gray-200 p-3 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none bg-white" placeholder="••••••••" value={formData.adminPassword} onChange={e => setFormData({...formData, adminPassword: e.target.value})} />
                            </div>
                        </>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full py-8 text-center text-gray-400 italic">
                            <ShieldCheck size={40} className="mb-2 opacity-20" />
                            <p className="text-xs">Utilisez l'onglet "Tous les Staffs" pour gérer les accès de cette pharmacie.</p>
                        </div>
                    )}
                  </div>
               </div>

               <div className="flex gap-4 pt-4">
                  <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 bg-gray-100 text-gray-600 rounded-xl font-bold hover:bg-gray-200 transition">
                    Annuler
                  </button>
                  <button 
                    type="submit" 
                    disabled={isProcessing} 
                    className={`flex-[2] py-4 rounded-xl font-bold text-white shadow-xl transition flex justify-center items-center gap-2 transform active:scale-95 ${
                        editingPharma ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-pharmacy-600 hover:bg-pharmacy-700'
                    }`}
                  >
                    {isProcessing ? <Loader2 className="animate-spin" /> : <CheckCircle size={20} />}
                    {isProcessing ? 'Enregistrement...' : editingPharma ? 'Enregistrer les modifications' : 'Déployer maintenant'}
                  </button>
               </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default SuperAdminDashboard;

import React, { useState } from 'react';
import { User, Pharmacy } from '../types';
import { Lock, User as UserIcon, Activity, AlertCircle } from 'lucide-react';

interface LoginProps {
  users: User[];
  pharmacies?: Pharmacy[];
  onLogin: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ users, pharmacies = [], onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const user = users.find(u => u.username === username && u.password === password);

    if (user) {
      // Si ce n'est pas un super admin, on vérifie si sa pharmacie est active
      if (user.role !== 'SUPER_ADMIN' && user.pharmacyId) {
        const pharma = pharmacies.find(p => p.id === user.pharmacyId);
        if (pharma && pharma.status === 'SUSPENDED') {
          setError('Votre établissement a été suspendu par le Super Admin.');
          return;
        }
      }
      onLogin(user);
    } else {
      setError('Identifiants incorrects');
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col justify-center items-center p-4">
      <div className="max-w-md w-full bg-white rounded-2xl shadow-xl overflow-hidden">
        <div className="bg-pharmacy-600 p-8 text-center">
          <div className="inline-flex p-3 bg-white/20 rounded-full mb-4">
            <Activity className="text-white w-8 h-8" />
          </div>
          <h1 className="text-2xl font-bold text-white">Fasopharm</h1>
          <p className="text-pharmacy-100 mt-2">Gestion de Pharmacie Sécurisée</p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          {error && (
            <div className="bg-red-50 text-red-600 p-4 rounded-xl text-sm flex items-center gap-3 border border-red-100 animate-shake">
              <AlertCircle size={20} className="shrink-0" />
              <p className="font-medium">{error}</p>
            </div>
          )}

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Nom d'utilisateur</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <UserIcon className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  type="text"
                  required
                  className="pl-10 w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-pharmacy-500 focus:border-pharmacy-500 outline-none transition"
                  placeholder="ex: admin"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Mot de passe</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Lock className="h-5 w-5 text-gray-400" />
                </div>
                <input
                  type="password"
                  required
                  className="pl-10 w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-pharmacy-500 focus:border-pharmacy-500 outline-none transition"
                  placeholder="••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                />
              </div>
            </div>
          </div>

          <button
            type="submit"
            className="w-full bg-pharmacy-600 text-white py-4 rounded-xl font-bold hover:bg-pharmacy-700 transition duration-200 shadow-lg transform active:scale-95 text-lg"
          >
            Se connecter
          </button>

          <div className="text-center">
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Comptes de Test</p>
            <div className="flex flex-wrap justify-center gap-2">
                <span className="px-2 py-1 bg-gray-100 rounded text-[10px] text-gray-500 font-mono">superadmin / root</span>
                <span className="px-2 py-1 bg-gray-100 rounded text-[10px] text-gray-500 font-mono">admin / 123</span>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { ViewState, Drug, Sale, User, UserRole, Supplier, Insurance, PendingOrder, Pharmacy } from './types';
import { INITIAL_DRUGS, INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_INSURANCES, INITIAL_PHARMACIES } from './constants';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import POS from './components/POS';
import AIAssistant from './components/AIAssistant';
import PrescriptionScanner from './components/PrescriptionScanner';
import Login from './components/Login';
import UserManagement from './components/UserManagement';
import SalesHistory from './components/SalesHistory';
import Suppliers from './components/Suppliers';
import Insurances from './components/Insurances';
import DataExport from './components/DataExport';
import Orders from './components/Orders';
import CashClosing from './components/CashClosing';
import SuperAdminDashboard from './components/SuperAdminDashboard';

import { 
  LayoutDashboard, Package, ShoppingCart, Bot, ScanLine, Activity, LogOut, Users, Bell, 
  History, Truck, ShieldCheck, Database, ShoppingBag, Wallet,
  ChevronDown, ChevronRight, Layers, FileText, BrainCircuit, Building2, Globe
} from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>(INITIAL_PHARMACIES);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  const [drugs, setDrugs] = useState<Drug[]>(INITIAL_DRUGS);
  const [sales, setSales] = useState<Sale[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>(INITIAL_SUPPLIERS);
  const [insurances, setInsurances] = useState<Insurance[]>(INITIAL_INSURANCES);
  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>([]);

  const [showNotifications, setShowNotifications] = useState(false);

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'SUPER_ADMIN') setCurrentView(ViewState.SUPER_ADMIN_DASHBOARD);
      else if (currentUser.role === 'CASHIER') setCurrentView(ViewState.POS);
      else if (currentUser.role === 'AGENT') setCurrentView(ViewState.INVENTORY);
      else if (currentUser.role === 'SELLER') setCurrentView(ViewState.POS);
      else setCurrentView(ViewState.DASHBOARD);
    }
  }, [currentUser]);

  const handleLogout = () => {
    setCurrentUser(null);
  };

  if (!currentUser) {
    return <Login users={users} pharmacies={pharmacies} onLogin={setCurrentUser} />;
  }

  // Filtrage des données par pharmacie pour les utilisateurs non-super-admin
  const currentPharmacyId = currentUser.pharmacyId;
  const filteredDrugs = currentUser.role === 'SUPER_ADMIN' ? drugs : drugs.filter(d => d.pharmacyId === currentPharmacyId);
  const filteredSales = currentUser.role === 'SUPER_ADMIN' ? sales : sales.filter(s => s.pharmacyId === currentPharmacyId);
  const filteredSuppliers = currentUser.role === 'SUPER_ADMIN' ? suppliers : suppliers.filter(s => s.pharmacyId === currentPharmacyId);
  const filteredInsurances = currentUser.role === 'SUPER_ADMIN' ? insurances : insurances.filter(i => i.pharmacyId === currentPharmacyId);

  const renderContent = () => {
    switch (currentView) {
      case ViewState.SUPER_ADMIN_DASHBOARD:
        return <SuperAdminDashboard pharmacies={pharmacies} setPharmacies={setPharmacies} users={users} setUsers={setUsers} />;
      case ViewState.DASHBOARD:
        return <Dashboard drugs={filteredDrugs} sales={filteredSales} />;
      case ViewState.INVENTORY:
        return <Inventory drugs={filteredDrugs} setDrugs={setDrugs} currentUser={currentUser} />;
      case ViewState.POS:
        return (
          <POS 
            drugs={filteredDrugs} setDrugs={setDrugs} insurances={filteredInsurances} 
            onSaleComplete={(s) => setSales([...sales, {...s, pharmacyId: currentPharmacyId || ''}])} 
            currentUser={currentUser} pendingOrders={pendingOrders} setPendingOrders={setPendingOrders}
          />
        );
      case ViewState.ASSISTANT:
        return <AIAssistant drugs={filteredDrugs} sales={filteredSales} suppliers={filteredSuppliers} insurances={filteredInsurances} />;
      case ViewState.SCANNER:
        return <PrescriptionScanner />;
      case ViewState.USERS:
        return <UserManagement users={users} setUsers={setUsers} currentUser={currentUser} pharmacies={pharmacies} />;
      case ViewState.SALES_HISTORY:
        return <SalesHistory sales={filteredSales} />;
      case ViewState.SUPPLIERS:
        return <Suppliers suppliers={filteredSuppliers} setSuppliers={setSuppliers} />;
      case ViewState.INSURANCES:
        return <Insurances insurances={filteredInsurances} setInsurances={setInsurances} />;
      case ViewState.EXPORTS:
        return <DataExport drugs={filteredDrugs} sales={filteredSales} users={users} suppliers={filteredSuppliers} insurances={filteredInsurances} />;
      case ViewState.ORDERS:
        return <Orders drugs={filteredDrugs} suppliers={filteredSuppliers} />;
      default:
        return null;
    }
  };

  const NavItem = ({ view, icon: Icon, label, allowedRoles }: { view: ViewState, icon: any, label: string, allowedRoles: UserRole[] }) => {
    if (!allowedRoles.includes(currentUser.role)) return null;
    const isActive = currentView === view;
    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 mb-1 ${
          isActive 
          ? 'bg-pharmacy-600 text-white shadow-md' 
          : 'text-gray-600 hover:bg-pharmacy-50 hover:text-pharmacy-700'
        }`}
      >
        <Icon size={20} className={isActive ? 'text-white' : 'text-gray-500'} />
        <span className="font-medium">{label}</span>
      </button>
    );
  };

  return (
    <div className="flex h-screen bg-gray-100 font-sans overflow-hidden text-sm md:text-base">
      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col shadow-sm z-10">
        <div className="p-6 flex items-center space-x-3 border-b border-gray-100">
          <div className="bg-pharmacy-600 p-2 rounded-lg text-white shadow-md"><Activity size={24} /></div>
          <div>
            <h1 className="text-xl font-bold text-gray-800 tracking-tight">Fasopharm</h1>
            <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">{currentUser.role}</p>
          </div>
        </div>

        <nav className="flex-1 p-3 space-y-1 overflow-y-auto custom-scrollbar">
          {currentUser.role === 'SUPER_ADMIN' ? (
            <>
              <div className="px-4 py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">Master Control</div>
              <NavItem view={ViewState.SUPER_ADMIN_DASHBOARD} icon={Globe} label="Réseau Global" allowedRoles={['SUPER_ADMIN']} />
              <NavItem view={ViewState.USERS} icon={Users} label="Tous les Staffs" allowedRoles={['SUPER_ADMIN']} />
              <NavItem view={ViewState.EXPORTS} icon={Database} label="Archives Cloud" allowedRoles={['SUPER_ADMIN']} />
            </>
          ) : (
            <>
              <div className="px-4 py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                {pharmacies.find(p => p.id === currentPharmacyId)?.name || 'Espace Pharmacie'}
              </div>
              <NavItem view={ViewState.DASHBOARD} icon={LayoutDashboard} label="Tableau de Bord" allowedRoles={['ADMIN']} />
              <NavItem view={ViewState.POS} icon={ShoppingCart} label={currentUser.role === 'SELLER' ? "Préparation" : "Caisse"} allowedRoles={['ADMIN', 'CASHIER', 'SELLER']} />

              <div className="px-4 py-2 mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Logistique</div>
              <NavItem view={ViewState.INVENTORY} icon={Package} label="Stocks" allowedRoles={['ADMIN', 'AGENT']} />
              <NavItem view={ViewState.ORDERS} icon={ShoppingBag} label="Réappro" allowedRoles={['ADMIN', 'AGENT']} />

              <div className="px-4 py-2 mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Intelligence</div>
              <NavItem view={ViewState.ASSISTANT} icon={BrainCircuit} label="Assistant IA" allowedRoles={['ADMIN', 'AGENT', 'SELLER', 'CASHIER']} />
              <NavItem view={ViewState.SCANNER} icon={ScanLine} label="Scan Ordonnance" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} />

              {currentUser.role === 'ADMIN' && (
                <>
                  <div className="px-4 py-2 mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Gestion Locale</div>
                  <NavItem view={ViewState.SALES_HISTORY} icon={History} label="Historique Ventes" allowedRoles={['ADMIN']} />
                  <NavItem view={ViewState.USERS} icon={Users} label="Mon Personnel" allowedRoles={['ADMIN']} />
                </>
              )}
            </>
          )}
        </nav>

        <div className="p-4 border-t border-gray-100">
          <div className="mb-4 px-2">
            <p className="text-[10px] font-bold text-gray-400 uppercase">Utilisateur</p>
            <p className="font-bold text-gray-700 truncate">{currentUser.fullName}</p>
          </div>
          <button onClick={handleLogout} className="w-full flex items-center justify-center gap-2 p-2 text-red-600 hover:bg-red-50 rounded-lg transition text-sm font-bold">
            <LogOut size={18} /> Déconnexion
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6 shadow-sm z-20">
          <h2 className="text-xl font-bold text-gray-800">{currentView}</h2>
          {currentUser.role !== 'SUPER_ADMIN' && (
            <div className="flex items-center gap-2 text-pharmacy-600 bg-pharmacy-50 px-3 py-1.5 rounded-full border border-pharmacy-100">
              <Building2 size={16} />
              <span className="text-xs font-black uppercase tracking-tight">{pharmacies.find(p => p.id === currentPharmacyId)?.name}</span>
            </div>
          )}
        </header>
        <div className="flex-1 overflow-auto bg-gray-50 relative">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Drug, CartItem, Sale, PaymentMethod, User, Insurance, PendingOrder, Pharmacy } from '../types';
import { ShoppingCart, Plus, Minus, Trash, Search, AlertOctagon, CreditCard, Banknote, Smartphone, Printer, CheckCircle, ShieldCheck, Camera, Loader2, User as UserIcon, FileText, Send, Clock, X, RefreshCw, ChevronDown, ChevronUp, Coins, Store, MapPin, Phone } from 'lucide-react';
import { checkDrugInteractions, analyzeMedicineBox } from '../services/geminiService';

interface POSProps {
  drugs: Drug[];
  setDrugs: React.Dispatch<React.SetStateAction<Drug[]>>;
  insurances: Insurance[];
  onSaleComplete: (sale: Sale) => void;
  currentUser: User;
  pendingOrders: PendingOrder[];
  setPendingOrders: React.Dispatch<React.SetStateAction<PendingOrder[]>>;
  pharmacies: Pharmacy[]; // Ajout des pharmacies pour l'affichage dynamique
}

const POS: React.FC<POSProps> = ({ drugs, setDrugs, insurances, onSaleComplete, currentUser, pendingOrders, setPendingOrders, pharmacies }) => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [interactionAlert, setInteractionAlert] = useState<string | null>(null);
  const [isChecking, setIsChecking] = useState(false);
  const [isScanning, setIsScanning] = useState(false);

  const [showInsurance, setShowInsurance] = useState(false);
  const [selectedInsuranceId, setSelectedInsuranceId] = useState<string>('');
  const [coverageRate, setCoverageRate] = useState<number>(0);

  const [patientName, setPatientName] = useState('');
  const [policyNumber, setPolicyNumber] = useState('');

  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('CASH');
  const [amountReceived, setAmountReceived] = useState<number | ''>(''); 

  const [showReceipt, setShowReceipt] = useState<Sale | null>(null);
  const [showPendingTicket, setShowPendingTicket] = useState<PendingOrder | null>(null);

  const isPreparer = currentUser.role === 'SELLER' || currentUser.role === 'AGENT';
  const isCashier = currentUser.role === 'CASHIER' || currentUser.role === 'ADMIN';

  const searchInputRef = useRef<HTMLInputElement>(null);
  const cashInputRef = useRef<HTMLInputElement>(null);

  // Get Current Pharmacy Details
  const currentPharmacy = pharmacies.find(p => p.id === currentUser.pharmacyId) || pharmacies[0];

  const localPendingOrders = pendingOrders.filter(order => order.pharmacyId === currentUser.pharmacyId);

  const totalAmount = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const insuranceAmount = selectedInsuranceId ? Math.round(totalAmount * (coverageRate / 100)) : 0;
  const patientAmount = totalAmount - insuranceAmount;

  const amountToPay = patientAmount; 
  const changeDue = typeof amountReceived === 'number' ? amountReceived - amountToPay : 0;
  const isAmountSufficient = paymentMethod !== 'CASH' || (typeof amountReceived === 'number' && amountReceived >= amountToPay);

  useEffect(() => {
    if (searchInputRef.current) searchInputRef.current.focus();
  }, []);

  const handleInsuranceChange = (id: string) => {
    setSelectedInsuranceId(id);
    if (id) {
      const ins = insurances.find(i => i.id === id);
      setCoverageRate(ins ? ins.defaultCoverage : 0);
    } else {
      setCoverageRate(0);
      setPatientName('');
      setPolicyNumber('');
    }
  };

  const addToCart = (drug: Drug) => {
    const existing = cart.find(item => item.id === drug.id);
    if (existing) {
      if (existing.quantity < drug.stock) {
        setCart(cart.map(item => item.id === drug.id ? { ...item, quantity: item.quantity + 1 } : item));
      } else {
        alert("Stock insuffisant !");
      }
    } else {
      if (drug.stock > 0) {
        setCart([...cart, { ...drug, quantity: 1 }]);
      } else {
        alert("Produit en rupture de stock.");
      }
    }
    setSearchTerm('');
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        const drug = drugs.find(d => d.id === id);
        if (newQty > 0 && drug && newQty <= drug.stock) {
          return { ...item, quantity: newQty };
        }
      }
      return item;
    }));
  };

  const handleSendToCashier = () => {
    if (cart.length === 0) return;
    const newOrder: PendingOrder = {
      id: Date.now().toString(),
      pharmacyId: currentUser.pharmacyId || '',
      ticketNumber: `T-${Math.floor(Math.random() * 900) + 100}`,
      timestamp: new Date(),
      items: [...cart],
      total: totalAmount,
      preparedBy: currentUser.fullName,
      insuranceId: selectedInsuranceId,
      patientName,
      policyNumber
    };
    setPendingOrders(prev => [...prev, newOrder]);
    setCart([]);
    setShowPendingTicket(newOrder);
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;
    if (selectedInsuranceId && (!patientName.trim() || !policyNumber.trim())) {
      alert("Infos patient requises pour l'assurance.");
      return;
    }
    if (!isAmountSufficient) {
       alert("Montant reçu insuffisant.");
       return;
    }

    const newDrugs = drugs.map(d => {
      const cartItem = cart.find(c => c.id === d.id);
      if (cartItem) return { ...d, stock: d.stock - cartItem.quantity };
      return d;
    });
    setDrugs(newDrugs);

    const selectedIns = insurances.find(i => i.id === selectedInsuranceId);
    const sale: Sale = {
      id: `S${Date.now().toString().slice(-8)}`,
      pharmacyId: currentUser.pharmacyId || '',
      timestamp: new Date(),
      items: [...cart],
      total: totalAmount,
      paymentMethod: paymentMethod,
      servedBy: currentUser.fullName,
      insuranceId: selectedInsuranceId || undefined,
      insuranceName: selectedIns?.name,
      insuranceCoverageRate: selectedInsuranceId ? coverageRate : undefined,
      insuranceAmount: selectedInsuranceId ? insuranceAmount : 0,
      patientAmount: patientAmount,
      patientName: selectedInsuranceId ? patientName : undefined,
      policyNumber: selectedInsuranceId ? policyNumber : undefined,
      amountReceived: paymentMethod === 'CASH' && typeof amountReceived === 'number' ? amountReceived : undefined,
      changeGiven: paymentMethod === 'CASH' ? changeDue : undefined
    };

    onSaleComplete(sale);
    setCart([]);
    setShowReceipt(sale);
  };

  const formatCurrency = (value: number) => value.toLocaleString('fr-FR') + ' FCFA';

  const PendingTicketModal = () => {
      if (!showPendingTicket) return null;
      return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm animate-fade-in">
            <div className="bg-white p-8 rounded-2xl shadow-2xl w-80 text-center border-t-4 border-pharmacy-500">
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">{currentPharmacy.name}</p>
                <h3 className="text-xl font-bold text-gray-800">Ticket de Préparation</h3>
                <div className="bg-gray-100 p-6 rounded-xl border-2 border-dashed border-gray-300 my-6">
                    <p className="text-5xl font-mono font-black text-gray-900">{showPendingTicket.ticketNumber}</p>
                </div>
                <p className="text-xs text-gray-500 mb-6 italic">Veuillez présenter ce numéro à la caisse pour le règlement.</p>
                <button onClick={() => setShowPendingTicket(null)} className="w-full py-3 bg-pharmacy-600 text-white rounded-xl hover:bg-pharmacy-700 font-bold shadow-lg">Terminer</button>
            </div>
        </div>
      );
  }

  const ReceiptModal = () => {
    if (!showReceipt) return null;
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm animate-fade-in">
        <div className="bg-white rounded-2xl shadow-2xl w-96 overflow-hidden flex flex-col max-h-[90vh]">
          <div className="bg-gray-800 text-white p-6 text-center">
            <h3 className="font-black uppercase tracking-widest">Reçu de Vente</h3>
          </div>

          <div className="p-8 bg-white font-mono text-sm overflow-y-auto flex-1">
            <div className="text-center mb-6">
              <p className="font-black text-2xl uppercase tracking-tighter text-gray-900">{currentPharmacy.name}</p>
              <p className="text-[10px] text-gray-500 mt-1 uppercase font-bold">{currentPharmacy.address}</p>
              <p className="text-[10px] text-gray-500 font-bold">TEL: {currentPharmacy.phone}</p>
            </div>

            <div className="border-b border-dashed border-gray-300 my-4"></div>

            <div className="flex justify-between text-[10px] mb-4 text-gray-500">
              <span>REÇU: {showReceipt.id}</span>
              <span>{new Date(showReceipt.timestamp).toLocaleString()}</span>
            </div>

            {showReceipt.insuranceName && (
              <div className="my-4 border border-indigo-200 p-3 rounded-lg text-[11px] bg-indigo-50">
                <p className="font-black text-indigo-800">ASSURANCE: {showReceipt.insuranceName}</p>
                <p>PATIENT: {showReceipt.patientName}</p>
                <p>MATRICULE: {showReceipt.policyNumber}</p>
              </div>
            )}

            <div className="space-y-3 mb-6">
              {showReceipt.items.map((item, idx) => (
                <div key={idx} className="flex justify-between items-start">
                  <span className="max-w-[180px] leading-tight">{item.quantity} x {item.name}</span>
                  <span className="font-bold">{formatCurrency(item.price * item.quantity)}</span>
                </div>
              ))}
            </div>

            <div className="border-b border-dashed border-gray-300 my-4"></div>

            <div className="space-y-1">
                <div className="flex justify-between font-bold text-gray-600">
                  <span>TOTAL BRUT</span>
                  <span>{formatCurrency(showReceipt.total)}</span>
                </div>

                {showReceipt.insuranceName && (
                   <div className="flex justify-between text-indigo-600 font-bold">
                       <span>PART TIERS-PAYANT ({showReceipt.insuranceCoverageRate}%)</span>
                       <span>-{formatCurrency(showReceipt.insuranceAmount || 0)}</span>
                   </div>
                )}

                <div className="flex justify-between font-black text-xl text-gray-900 pt-4 mt-2 border-t border-gray-100">
                  <span>NET À PAYER</span>
                  <span>{formatCurrency(showReceipt.patientAmount || showReceipt.total)}</span>
                </div>

                {showReceipt.paymentMethod === 'CASH' && (
                    <div className="mt-4 pt-4 border-t border-gray-50 space-y-1 text-right text-xs">
                      <div className="text-gray-400">ESPÈCES REÇU: {formatCurrency(showReceipt.amountReceived || 0)}</div>
                      <div className="font-black text-gray-800">MONNAIE RENDUE: {formatCurrency(showReceipt.changeGiven || 0)}</div>
                    </div>
                )}
            </div>

            <div className="text-center mt-10 space-y-1">
              <p className="text-[10px] text-gray-400 font-bold">MODE: {showReceipt.paymentMethod}</p>
              <p className="text-[10px] text-gray-400 font-bold">SERVI PAR: {showReceipt.servedBy}</p>
              <p className="text-xs font-black mt-4 uppercase">*** Merci de votre confiance ***</p>
            </div>
          </div>

          <div className="p-4 bg-gray-50 flex gap-3 border-t border-gray-200">
             <button onClick={() => setShowReceipt(null)} className="flex-1 py-4 bg-gray-200 text-gray-800 rounded-xl font-bold hover:bg-gray-300">Fermer</button>
             <button onClick={() => { window.print(); setShowReceipt(null); }} className="flex-[2] py-4 bg-pharmacy-600 text-white rounded-xl font-bold hover:bg-pharmacy-700 flex justify-center items-center gap-2 shadow-lg">
               <Printer size={20} /> Imprimer Reçu
             </button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="flex h-full bg-gray-100 overflow-hidden relative">
      {showReceipt && <ReceiptModal />}
      {showPendingTicket && <PendingTicketModal />}

      {/* Pending Orders Bar */}
      {isCashier && localPendingOrders.length > 0 && (
          <div className="w-64 bg-white border-r border-gray-200 flex flex-col z-20 shadow-xl">
              <div className="p-4 bg-indigo-600 text-white">
                  <h3 className="font-black text-xs uppercase tracking-widest flex items-center gap-2">
                      <Clock size={14} /> Tickets en attente
                  </h3>
              </div>
              <div className="flex-1 overflow-y-auto p-3 space-y-3">
                  {localPendingOrders.map(order => (
                      <div key={order.id} onClick={() => {setCart(order.items); if(order.insuranceId) handleInsuranceChange(order.insuranceId); setPendingOrders(prev => prev.filter(o => o.id !== order.id));}} className="p-4 bg-white border-2 border-gray-100 rounded-xl hover:border-pharmacy-400 hover:shadow-md cursor-pointer transition">
                          <div className="flex justify-between items-center mb-2">
                              <span className="font-mono font-black text-2xl text-pharmacy-600">{order.ticketNumber}</span>
                              <span className="text-[10px] font-bold text-gray-400">{new Date(order.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                          </div>
                          <p className="text-[10px] font-black text-gray-400 uppercase truncate">Par: {order.preparedBy}</p>
                          <p className="text-sm font-black text-gray-800 mt-1">{formatCurrency(order.total)}</p>
                      </div>
                  ))}
              </div>
          </div>
      )}

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white border-b border-gray-200 shadow-sm z-10">
           <div className="flex gap-4 max-w-5xl mx-auto">
              <div className="relative flex-1">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                <input ref={searchInputRef} type="text" placeholder="Rechercher un produit..." className="w-full pl-12 pr-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-pharmacy-500 outline-none text-lg" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
              </div>
              <label className="flex items-center gap-2 px-6 py-3 bg-white border border-gray-200 rounded-xl cursor-pointer hover:bg-gray-50 transition font-bold shadow-sm">
                 {isScanning ? <Loader2 className="animate-spin" size={20} /> : <Camera size={20} />}
                 <span className="hidden md:inline">Scanner IA</span>
                 <input type="file" accept="image/*" className="hidden" onChange={async (e) => {
                    const file = e.target.files?.[0];
                    if (file) {
                        setIsScanning(true);
                        const reader = new FileReader();
                        reader.onloadend = async () => {
                            const result = await analyzeMedicineBox(reader.result as string);
                            if (result?.name) {
                                const found = drugs.find(d => d.name.toLowerCase().includes(result.name!.toLowerCase()));
                                if (found) addToCart(found);
                                else alert(`Produit "${result.name}" non trouvé en stock.`);
                            }
                            setIsScanning(false);
                        };
                        reader.readAsDataURL(file);
                    }
                 }} />
              </label>
           </div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-gray-50">
           <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6 max-w-6xl mx-auto">
              {drugs.filter(d => d.name.toLowerCase().includes(searchTerm.toLowerCase())).map(drug => (
                <div key={drug.id} onClick={() => addToCart(drug)} className={`bg-white p-4 rounded-2xl border-2 transition shadow-sm hover:shadow-xl cursor-pointer flex flex-col justify-between h-52 group relative overflow-hidden ${drug.stock === 0 ? 'opacity-50 pointer-events-none' : 'border-white hover:border-pharmacy-400'}`}>
                  {drug.stock < 20 && drug.stock > 0 && <div className="absolute top-0 right-0 bg-red-500 text-white text-[10px] px-3 py-1 font-black rounded-bl-xl">STOCK BAS</div>}
                  <div>
                    <h3 className="font-black text-gray-800 leading-tight group-hover:text-pharmacy-600 transition">{drug.name}</h3>
                    <p className="text-[10px] font-black text-gray-400 uppercase mt-1">{drug.category}</p>
                    <p className="text-[10px] text-gray-400 font-bold">{drug.dosage}</p>
                  </div>
                  <div className="mt-4 border-t border-gray-50 pt-3">
                    <p className="font-black text-2xl text-gray-900">{formatCurrency(drug.price).split(' ')[0]} <span className="text-[10px] text-gray-400">F</span></p>
                    <p className={`text-[10px] font-black uppercase mt-1 ${drug.stock > 0 ? 'text-green-500' : 'text-red-500'}`}>
                       {drug.stock > 0 ? `${drug.stock} Disponibles` : 'Rupture'}
                    </p>
                  </div>
                </div>
              ))}
           </div>
        </div>
      </div>

      {/* Cart Panel */}
      <div className="w-[420px] bg-white border-l border-gray-200 shadow-2xl flex flex-col h-full z-30">
          <div className="p-5 bg-gray-900 text-white flex justify-between items-center shadow-lg">
             <div className="flex items-center gap-3">
                <div className="p-2 bg-pharmacy-600 rounded-lg"><ShoppingCart size={20} /></div>
                <div>
                    <h3 className="font-black text-sm uppercase tracking-widest">{isPreparer && !isCashier ? 'Préparation' : 'Caisse'}</h3>
                    <p className="text-[10px] text-gray-400 font-bold uppercase">{currentPharmacy.name}</p>
                </div>
             </div>
             {cart.length > 0 && <button onClick={() => setCart([])} className="text-gray-500 hover:text-white transition"><Trash size={20} /></button>}
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-gray-50">
             {cart.length === 0 ? (
               <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-20 text-center px-10">
                 <ShoppingCart size={80} strokeWidth={1} />
                 <p className="mt-4 font-black uppercase tracking-widest text-sm">Le panier est vide</p>
               </div>
             ) : (
               cart.map(item => (
                 <div key={item.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm animate-fade-in">
                    <div className="flex justify-between items-start mb-2">
                        <span className="font-black text-gray-800 leading-tight">{item.name}</span>
                        <button onClick={() => removeFromCart(item.id)} className="text-gray-300 hover:text-red-500 transition"><X size={18} /></button>
                    </div>
                    <div className="flex justify-between items-center">
                        <div className="flex items-center bg-gray-100 rounded-xl p-1">
                            <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-white rounded-lg transition shadow-sm"><Minus size={14}/></button>
                            <span className="w-10 text-center font-black text-sm">{item.quantity}</span>
                            <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-white rounded-lg transition shadow-sm"><Plus size={14}/></button>
                        </div>
                        <span className="font-black text-gray-900">{formatCurrency(item.price * item.quantity)}</span>
                    </div>
                 </div>
               ))
             )}
          </div>

          <div className="bg-white p-6 border-t border-gray-100 shadow-2xl">
             <div className="space-y-3 mb-6">
                 <div className="flex justify-between text-gray-400 text-xs font-black uppercase tracking-widest">
