import React, { useState } from 'react';
import { Pharmacy, User } from '../types';
import { Building2, Plus, Users, ShieldCheck, Activity, Search, Edit2, Ban, CheckCircle, X, Store, MapPin, Phone, Loader2, Power } from 'lucide-react';

interface SuperAdminDashboardProps {
  pharmacies: Pharmacy[];
  setPharmacies: React.Dispatch<React.SetStateAction<Pharmacy[]>>;
  users: User[];
  setUsers: React.Dispatch<React.SetStateAction<User[]>>;
}

const SuperAdminDashboard: React.FC<SuperAdminDashboardProps> = ({ pharmacies, setPharmacies, users, setUsers }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [editingPharma, setEditingPharma] = useState<Pharmacy | null>(null);

  const [formData, setFormData] = useState({
    name: '',
    address: '',
    phone: '',
    adminName: '',
    adminUsername: '',
    adminPassword: ''
  });

  const handleToggleStatus = (id: string) => {
    const pharma = pharmacies.find(p => p.id === id);
    if (!pharma) return;

    const isCurrentlyActive = pharma.status === 'ACTIVE';
    const nextStatus = isCurrentlyActive ? 'SUSPENDED' : 'ACTIVE';
    const actionLabel = isCurrentlyActive ? 'SUSPENDRE' : 'RÉACTIVER';

    if (window.confirm(`Action de sécurité : Voulez-vous vraiment ${actionLabel} l'accès pour "${pharma.name}" ?`)) {
      setPharmacies(current => 
        current.map(p => p.id === id ? { ...p, status: nextStatus as 'ACTIVE' | 'SUSPENDED' } : p)
      );
    }
  };

  const handleOpenCreate = () => {
    setEditingPharma(null);
    setFormData({ name: '', address: '', phone: '', adminName: '', adminUsername: '', adminPassword: '' });
    setIsModalOpen(true);
  };

  const handleOpenEdit = (pharma: Pharmacy) => {
    setEditingPharma(pharma);
    setFormData({
      name: pharma.name,
      address: pharma.address,
      phone: pharma.phone,
      adminName: '',
      adminUsername: '',
      adminPassword: ''
    });
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsProcessing(true);

    setTimeout(() => {
      if (editingPharma) {
        setPharmacies(prev => prev.map(p => 
          p.id === editingPharma.id 
          ? { ...p, name: formData.name, address: formData.address, phone: formData.phone } 
          : p
        ));
      } else {
        const pharmacyId = `pharma_${Date.now()}`;
        const newPharmacy: Pharmacy = {
          id: pharmacyId,
          name: formData.name,
          address: formData.address,
          phone: formData.phone,
          status: 'ACTIVE',
          createdAt: new Date()
        };

        const initialAdmin: User = {
          id: `user_${Date.now()}`,
          pharmacyId: pharmacyId,
          username: formData.adminUsername,
          password: formData.adminPassword,
          fullName: formData.adminName,
          role: 'ADMIN'
        };

        setPharmacies(prev => [...prev, newPharmacy]);
        setUsers(prev => [...prev, initialAdmin]);
      }

