                            </div>
                            <div>
                                <label className="block text-xs font-bold text-gray-600 mb-1">Identifiant</label>
                                <input required={!editingPharma} type="text" className="w-full border border-gray-200 p-3 rounded-xl bg-white" placeholder="admin_p1" value={formData.adminUsername} onChange={e => setFormData({...formData, adminUsername: e.target.value})} />
                            </div>
                            <div>
                                <label className="block text-xs font-bold text-gray-600 mb-1">Mot de Passe</label>
                                <input required={!editingPharma} type="text" className="w-full border border-gray-200 p-3 rounded-xl bg-white" placeholder="••••••••" value={formData.adminPassword} onChange={e => setFormData({...formData, adminPassword: e.target.value})} />
                            </div>
                        </>
                    ) : (
                        <div className="flex flex-col items-center justify-center py-10 text-center text-gray-400 italic">
                            <ShieldCheck size={48} className="mb-2 opacity-20" />
                            <p className="text-xs">Le mot de passe de l'administrateur se modifie via le menu Staff.</p>
                        </div>
                    )}
                  </div>
               </div>

               <div className="flex gap-4 pt-4">
                  <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 bg-gray-100 text-gray-600 rounded-xl font-bold hover:bg-gray-200 transition">
                    Annuler
                  </button>
                  <button 
                    type="submit" 
                    disabled={isProcessing} 
                    className={`flex-[2] py-4 rounded-xl font-bold text-white shadow-xl transition flex justify-center items-center gap-2 ${
                        editingPharma ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-pharmacy-600 hover:bg-pharmacy-700'
                    }`}
                  >
                    {isProcessing ? <Loader2 className="animate-spin" /> : <CheckCircle size={20} />}
                    {isProcessing ? 'Enregistrement...' : editingPharma ? 'Sauvegarder' : 'Déployer'}
                  </button>
               </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

