// URL de l'API : utilise une variable d'environnement en production, ou localhost en développement
const API_BASE_URL = process.env.NODE_ENV === 'production' 
  ? 'https://api.votre-domaine-pharmacie.com/api' 
  : 'http://localhost:8000/api';

const getHeaders = () => {
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
  };

  // Si vous utilisez un token d'authentification (Sanctum/JWT)
  const token = localStorage.getItem('auth_token');
  if (token) {
    headers['Authorization'] = `Bearer ${token}`;
  }

  return headers;
};

export const apiService = {
  // Drugs
  getDrugs: async () => {
    const res = await fetch(`${API_BASE_URL}/drugs`, { headers: getHeaders() });
    if (!res.ok) throw new Error('Erreur lors de la récupération des produits');
    return res.json();
  },

  saveDrug: async (drug: any) => {
    const isUpdate = drug.id && !drug.id.toString().startsWith('temp_') && !drug.id.toString().startsWith('drug_');
    const method = isUpdate ? 'PUT' : 'POST';
    const url = isUpdate ? `${API_BASE_URL}/drugs/${drug.id}` : `${API_BASE_URL}/drugs`;

    const res = await fetch(url, {
      method,
      headers: getHeaders(),
      body: JSON.stringify(drug)
    });
    return res.json();
  },

  deleteDrug: async (id: string) => {
    const res = await fetch(`${API_BASE_URL}/drugs/${id}`, { 
      method: 'DELETE', 
      headers: getHeaders() 
    });
    if (!res.ok) throw new Error('Erreur lors de la suppression');
  },

  // Sales
  getSales: async () => {
    const res = await fetch(`${API_BASE_URL}/sales`, { headers: getHeaders() });
    return res.json();
  },

  createSale: async (sale: any) => {
    const res = await fetch(`${API_BASE_URL}/sales`, {
      method: 'POST',
      headers: getHeaders(),
      body: JSON.stringify(sale)
    });
    return res.json();
  },

  // Auth
  login: async (credentials: any) => {
    const res = await fetch(`${API_BASE_URL}/login`, {
      method: 'POST',
      headers: getHeaders(),
      body: JSON.stringify(credentials)
    });
    if (!res.ok) throw new Error('Identifiants invalides');
    const data = await res.json();
    if (data.token) localStorage.setItem('auth_token', data.token);
    return data;
  },

  // Infrastructure
  getSuppliers: async () => {
    const res = await fetch(`${API_BASE_URL}/suppliers`, { headers: getHeaders() });
    return res.json();
  },

  getInsurances: async () => {
    const res = await fetch(`${API_BASE_URL}/insurances`, { headers: getHeaders() });
    return res.json();
  }
};

import { Drug, Sale, User, Supplier, Insurance, Pharmacy } from '../types';

// Clé de stockage pour le LocalStorage
const STORAGE_KEY = 'fasopharm_db';

// Structure de la base de données locale
interface LocalDB {
  drugs: Drug[];
  sales: Sale[];
  suppliers: Supplier[];
  insurances: Insurance[];
  users: User[];
  pharmacies: Pharmacy[];
}

// Initialisation de la DB locale si vide
const getDB = (): LocalDB => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) return { drugs: [], sales: [], suppliers: [], insurances: [], users: [], pharmacies: [] };
  return JSON.parse(data);
};

const saveDB = (db: LocalDB) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
};

export const apiService = {
  // Drugs
  getDrugs: async (): Promise<Drug[]> => {
    return getDB().drugs;
  },

  saveDrug: async (drug: any): Promise<Drug> => {
    const db = getDB();
    const id = drug.id && !drug.id.toString().startsWith('temp_') ? drug.id : `drug_${Date.now()}`;
    const newDrug = { ...drug, id };

    const index = db.drugs.findIndex(d => d.id === id);
    if (index > -1) {
      db.drugs[index] = newDrug;
    } else {
      db.drugs.push(newDrug);
    }

    saveDB(db);
    return newDrug;
  },

  deleteDrug: async (id: string): Promise<void> => {
    const db = getDB();
    db.drugs = db.drugs.filter(d => d.id !== id);
    saveDB(db);
  },

  // Sales
  getSales: async (): Promise<Sale[]> => {
    return getDB().sales;
  },

  createSale: async (sale: any): Promise<Sale> => {
    const db = getDB();
    const newSale = { ...sale, id: `sale_${Date.now()}` };
    db.sales.push(newSale);

    // Mettre à jour les stocks localement
    sale.items.forEach((item: any) => {
      const drug = db.drugs.find(d => d.id === item.id);
      if (drug) drug.stock -= item.quantity;
    });

    saveDB(db);
    return newSale;
  },

  // Infrastructure & Auth (Simulation)
  getSuppliers: async (): Promise<Supplier[]> => {
    return getDB().suppliers;
  },

  getInsurances: async (): Promise<Insurance[]> => {
    return getDB().insurances;
  },

  // Utilitaires de démarrage pour peupler la DB locale la première fois
  seedInitialData: (initialData: Partial<LocalDB>) => {
    const db = getDB();
    if (db.pharmacies.length === 0) {
      saveDB({ ...db, ...initialData });
      console.log("Base de données locale initialisée avec succès.");
    }
  }
};

