        insurances: INITIAL_INSURANCES,
        pharmacies: INITIAL_PHARMACIES
      });

      // Chargement des données
      const [d, s, sup, ins] = await Promise.all([
        apiService.getDrugs(),
        apiService.getSales(),
        apiService.getSuppliers(),
        apiService.getInsurances()
      ]);

      setDrugs(d);
      setSales(s);
      setSuppliers(sup);
      setInsurances(ins);
      setIsLoading(false);
    };
    init();
