import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Analyse une ordonnance à partir d'une image en base64
 */
export const analyzePrescriptionImage = async (base64Image: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          inlineData: {
            mimeType: "image/jpeg",
            data: base64Image.split(',')[1]
          }
        },
        { text: "Agis en tant qu'expert pharmacien. Analyse cette ordonnance et retourne UNIQUEMENT un JSON structuré : { \"medications\": [{\"name\": \"\", \"dosage\": \"\", \"instructions\": \"\"}], \"notes\": \"\" }" }
      ],
      config: {
        responseMimeType: "application/json"
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return null;
  }
};

/**
 * Chatbot intelligent synchronisé avec le contexte de la pharmacie
 */
export const getChatResponse = async (history: any[], message: string, context: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: message,
      config: {
        systemInstruction: `Tu es l'assistant intelligent de Fasopharm. 
        Données actuelles de la pharmacie : ${context}. 
        Aide le personnel à trouver des médicaments, vérifier les stocks ou suggérer des alternatives. 
        Sois concis, précis et professionnel.`
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Je rencontre une difficulté technique pour répondre. Veuillez vérifier votre connexion.";
  }
};

import React, { useState, useEffect } from 'react';
import { ViewState, Drug, Sale, User, UserRole, Supplier, Insurance, PendingOrder, Pharmacy } from './types';
import { INITIAL_DRUGS, INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_INSURANCES, INITIAL_PHARMACIES } from './constants';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import POS from './components/POS';
import AIAssistant from './components/AIAssistant';
import PrescriptionScanner from './components/PrescriptionScanner';
import Login from './components/Login';
import UserManagement from './components/UserManagement';
import SalesHistory from './components/SalesHistory';
import Suppliers from './components/Suppliers';
import Insurances from './components/Insurances';
import DataExport from './components/DataExport';
import Orders from './components/Orders';
import CashClosing from './components/CashClosing';
import SuperAdminDashboard from './components/SuperAdminDashboard';

import { 
  LayoutDashboard, Package, ShoppingCart, Bot, ScanLine, Activity, LogOut, Users, 
  History, Truck, ShieldCheck, Database, ShoppingBag, Wallet,
  Building2, Globe, Loader2, BrainCircuit
} from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('fp_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>(() => {
    const saved = localStorage.getItem('fp_pharmacies');
    return saved ? JSON.parse(saved) : INITIAL_PHARMACIES;
  });
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  const [drugs, setDrugs] = useState<Drug[]>(() => {
    const saved = localStorage.getItem('fp_drugs');
    return saved ? JSON.parse(saved) : INITIAL_DRUGS;
  });
  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem('fp_sales');
    return saved ? JSON.parse(saved) : [];
  });
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => {
    const saved = localStorage.getItem('fp_suppliers');
    return saved ? JSON.parse(saved) : INITIAL_SUPPLIERS;
  });
  const [insurances, setInsurances] = useState<Insurance[]>(() => {
    const saved = localStorage.getItem('fp_insurances');
    return saved ? JSON.parse(saved) : INITIAL_INSURANCES;
  });
  const [pendingOrders, setPendingOrders] = useState<PendingOrder[]>([]);

  const [isLoading, setIsLoading] = useState(false);
  const [showCashClosing, setShowCashClosing] = useState(false);

  // Persistence Auto-Save
  useEffect(() => { localStorage.setItem('fp_drugs', JSON.stringify(drugs)); }, [drugs]);
  useEffect(() => { localStorage.setItem('fp_sales', JSON.stringify(sales)); }, [sales]);
  useEffect(() => { localStorage.setItem('fp_users', JSON.stringify(users)); }, [users]);
  useEffect(() => { localStorage.setItem('fp_pharmacies', JSON.stringify(pharmacies)); }, [pharmacies]);
  useEffect(() => { localStorage.setItem('fp_suppliers', JSON.stringify(suppliers)); }, [suppliers]);
  useEffect(() => { localStorage.setItem('fp_insurances', JSON.stringify(insurances)); }, [insurances]);

  const handleSaleComplete = (sale: Sale) => {
    setSales(prev => [sale, ...prev]);
    // Mise à jour du stock
    setDrugs(prevDrugs => prevDrugs.map(drug => {
      const soldItem = sale.items.find(item => item.id === drug.id);
      return soldItem ? { ...drug, stock: drug.stock - soldItem.quantity } : drug;
    }));
  };

  if (isLoading) {
    return (
      <div className="h-screen flex flex-col items-center justify-center bg-white text-pharmacy-600">
        <Loader2 className="animate-spin mb-4" size={48} />
        <p className="font-bold uppercase tracking-widest text-xs">Initialisation du Cloud...</p>
      </div>
    );
  }

  if (!currentUser) {
    return <Login users={users} pharmacies={pharmacies} onLogin={setCurrentUser} />;
  }

  const currentPharmacyId = currentUser.pharmacyId;
  const filteredDrugs = currentUser.role === 'SUPER_ADMIN' ? drugs : drugs.filter(d => d.pharmacyId === currentPharmacyId);
  const filteredSales = currentUser.role === 'SUPER_ADMIN' ? sales : sales.filter(s => s.pharmacyId === currentPharmacyId);
  const filteredSuppliers = currentUser.role === 'SUPER_ADMIN' ? suppliers : suppliers.filter(s => s.pharmacyId === currentPharmacyId);
  const filteredInsurances = currentUser.role === 'SUPER_ADMIN' ? insurances : insurances.filter(i => i.pharmacyId === currentPharmacyId);

  const renderContent = () => {
    switch (currentView) {
      case ViewState.SUPER_ADMIN_DASHBOARD:
        return <SuperAdminDashboard pharmacies={pharmacies} setPharmacies={setPharmacies} users={users} setUsers={setUsers} allDrugs={drugs} allSales={sales} />;
      case ViewState.DASHBOARD:
        return <Dashboard drugs={filteredDrugs} sales={filteredSales} />;
      case ViewState.INVENTORY:
        return <Inventory drugs={drugs} setDrugs={setDrugs} currentUser={currentUser} />;
      case ViewState.POS:
        return <POS drugs={filteredDrugs} setDrugs={setDrugs} insurances={filteredInsurances} onSaleComplete={handleSaleComplete} currentUser={currentUser} pendingOrders={pendingOrders} setPendingOrders={setPendingOrders} pharmacies={pharmacies} />;
      case ViewState.ASSISTANT:
        return <AIAssistant drugs={filteredDrugs} sales={filteredSales} suppliers={filteredSuppliers} insurances={filteredInsurances} onAddToCart={(d) => setCurrentView(ViewState.POS)} />;
      case ViewState.SCANNER:
        return <PrescriptionScanner />;
      case ViewState.USERS:
        return <UserManagement users={users} setUsers={setUsers} currentUser={currentUser} pharmacies={pharmacies} />;
      case ViewState.SALES_HISTORY:
        return <SalesHistory sales={filteredSales} />;
      case ViewState.SUPPLIERS:
        return <Suppliers suppliers={suppliers} setSuppliers={setSuppliers} />;
      case ViewState.INSURANCES:
        return <Insurances insurances={insurances} setInsurances={setInsurances} />;
      case ViewState.EXPORTS:
        return <DataExport drugs={filteredDrugs} sales={filteredSales} users={users} suppliers={filteredSuppliers} insurances={filteredInsurances} pharmacies={pharmacies} />;
      case ViewState.ORDERS:
        return <Orders drugs={filteredDrugs} suppliers={filteredSuppliers} />;
      default:
        return null;
    }
  };

  const NavItem = ({ view, icon: Icon, label, allowedRoles }: { view: ViewState, icon: any, label: string, allowedRoles: UserRole[] }) => {
    if (!allowedRoles.includes(currentUser.role)) return null;
    const isActive = currentView === view;
    return (
      <button onClick={() => setCurrentView(view)} className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 mb-1 ${isActive ? 'bg-pharmacy-600 text-white shadow-lg' : 'text-gray-500 hover:bg-pharmacy-50 hover:text-pharmacy-700'}`}>
        <Icon size={20} className={isActive ? 'text-white' : 'text-gray-400'} />
        <span className="font-bold text-sm">{label}</span>
      </button>
    );
  };

  return (
    <div className="flex h-screen bg-gray-50 font-sans overflow-hidden">
      {showCashClosing && <CashClosing sales={filteredSales} currentUser={currentUser} onClose={() => setShowCashClosing(false)} pharmacies={pharmacies} />}

      <aside className="w-64 bg-white border-r border-gray-200 flex flex-col shadow-sm">
        <div className="p-6 flex items-center space-x-3 border-b border-gray-100">
          <div className="bg-pharmacy-600 p-2 rounded-lg text-white shadow-md"><Activity size={24} /></div>
          <div>
            <h1 className="text-xl font-black text-gray-800 tracking-tighter">Fasopharm</h1>
            <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">{currentUser.role}</p>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
          {currentUser.role === 'SUPER_ADMIN' ? (
            <div className="space-y-1">
              <NavItem view={ViewState.SUPER_ADMIN_DASHBOARD} icon={Globe} label="Réseau Global" allowedRoles={['SUPER_ADMIN']} />
              <NavItem view={ViewState.USERS} icon={Users} label="Staff Réseau" allowedRoles={['SUPER_ADMIN']} />
              <NavItem view={ViewState.EXPORTS} icon={Database} label="Sauvegardes" allowedRoles={['SUPER_ADMIN']} />
            </div>
          ) : (
            <>
              <div className="pb-2 mb-2 border-b border-gray-100">
                <NavItem view={ViewState.DASHBOARD} icon={LayoutDashboard} label="Tableau de Bord" allowedRoles={['ADMIN']} />
                <NavItem view={ViewState.POS} icon={ShoppingCart} label="Caisse" allowedRoles={['ADMIN', 'CASHIER', 'SELLER']} />
              </div>

              <div className="pb-2 mb-2 border-b border-gray-100">
                <p className="px-4 py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">Logistique</p>
                <NavItem view={ViewState.INVENTORY} icon={Package} label="Stocks" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} />
                <NavItem view={ViewState.ORDERS} icon={ShoppingBag} label="Réappro" allowedRoles={['ADMIN', 'AGENT']} />
                <NavItem view={ViewState.SUPPLIERS} icon={Truck} label="Fournisseurs" allowedRoles={['ADMIN', 'AGENT']} />
              </div>

              <div className="pb-2 mb-2 border-b border-gray-100">
                <p className="px-4 py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest">IA & Diagnostic</p>
                <NavItem view={ViewState.ASSISTANT} icon={BrainCircuit} label="Assistant IA" allowedRoles={['ADMIN', 'AGENT', 'SELLER', 'CASHIER']} />
                <NavItem view={ViewState.SCANNER} icon={ScanLine} label="Scan Ordonnance" allowedRoles={['ADMIN', 'AGENT', 'SELLER']} />
              </div>
            </>
          )}
        </nav>

        <div className="p-4 border-t border-gray-100 bg-gray-50/50">
          <div className="mb-4 px-2">
            <p className="text-xs font-bold text-gray-400 truncate">{currentUser.fullName}</p>
            <p className="text-[10px] font-medium text-pharmacy-600 truncate">{pharmacies.find(p => p.id === currentPharmacyId)?.name || 'Central'}</p>
          </div>
          <button onClick={() => setCurrentUser(null)} className="w-full flex items-center justify-center gap-2 p-3 text-red-600 hover:bg-red-50 rounded-xl transition text-xs font-black uppercase">
            <LogOut size={16} /> Déconnexion
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6">
          <h2 className="text-lg font-black text-gray-800 uppercase tracking-tight">{currentView.replace('_', ' ')}</h2>
          <div className="flex items-center gap-4">
            {['ADMIN', 'CASHIER'].includes(currentUser.role) && (
               <button onClick={() => setShowCashClosing(true)} className="flex items-center gap-2 px-4 py-2 bg-pharmacy-50 text-pharmacy-700 rounded-xl text-xs font-black uppercase hover:bg-pharmacy-100 transition">
                   <Wallet size={16} /><span>Clôture Caisse</span>
               </button>
            )}
            <div className="flex items-center gap-2 px-3 py-1.5 bg-gray-100 rounded-full border border-gray-200">
                <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Connecté</span>
            </div>
          </div>
        </header>
        <div className="flex-1 overflow-auto bg-gray-50/50">{renderContent()}</div>
      </main>
    </div>
  );
};

