import React, { useState } from 'react';
import { Drug, User } from '../types';
import { Plus, Search, Trash2, Edit2, Package, CheckCircle, Loader2, X } from 'lucide-react';

interface InventoryProps {
  drugs: Drug[];
  setDrugs: React.Dispatch<React.SetStateAction<Drug[]>>;
  currentUser: User;
}

const Inventory: React.FC<InventoryProps> = ({ drugs, setDrugs, currentUser }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingDrug, setEditingDrug] = useState<Drug | null>(null);

  const canManage = currentUser.role === 'ADMIN' || currentUser.role === 'AGENT' || currentUser.role === 'SUPER_ADMIN';

  const [formData, setFormData] = useState<Partial<Drug>>({
    name: '',
    description: '',
    category: '',
    dosage: '',
    price: 0,
    stock: 0,
    expiryDate: ''
  });

  const handleOpenModal = (drug?: Drug) => {
    if (drug) {
      setEditingDrug(drug);
      setFormData(drug);
    } else {
      setEditingDrug(null);
      setFormData({ 
        name: '', 
        description: '', 
        category: '', 
        dosage: '', 
        price: 0, 
        stock: 0, 
        expiryDate: '',
        pharmacyId: currentUser.pharmacyId
      });
    }
    setIsModalOpen(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const newDrug = {
      ...formData,
      id: editingDrug ? editingDrug.id : `d_${Date.now()}`,
      pharmacyId: editingDrug ? editingDrug.pharmacyId : currentUser.pharmacyId
    } as Drug;

    if (editingDrug) {
      setDrugs(prev => prev.map(d => d.id === editingDrug.id ? newDrug : d));
    } else {
      setDrugs(prev => [...prev, newDrug]);
    }
    setIsModalOpen(false);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Confirmer la suppression ?')) {
      setDrugs(prev => prev.filter(d => d.id !== id));
    }
  };

  const filteredDrugs = drugs.filter(d => 
    (currentUser.role === 'SUPER_ADMIN' || d.pharmacyId === currentUser.pharmacyId) &&
    (d.name.toLowerCase().includes(searchTerm.toLowerCase()) || d.category.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  return (
    <div className="p-6 h-full flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-black text-gray-800 tracking-tight">Inventaire Local</h2>
          <p className="text-sm text-gray-400">Total : {filteredDrugs.length} références</p>
        </div>
        {canManage && (
          <button onClick={() => handleOpenModal()} className="bg-pharmacy-600 hover:bg-pharmacy-700 text-white px-6 py-3 rounded-xl flex items-center gap-2 transition shadow-lg font-bold">
            <Plus size={20} /><span>Nouveau Produit</span>
          </button>
        )}
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-gray-100 flex-1 flex flex-col overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50/50">
          <div className="relative max-w-md">
            <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
            <input 
              type="text" 
              placeholder="Rechercher un médicament..." 
              className="w-full pl-12 pr-4 py-3 border border-gray-200 rounded-2xl focus:outline-none focus:ring-2 focus:ring-pharmacy-500 bg-white transition shadow-inner" 
              value={searchTerm} 
              onChange={(e) => setSearchTerm(e.target.value)} 
            />
          </div>
        </div>

        <div className="overflow-auto flex-1">
          <table className="min-w-full divide-y divide-gray-100">
            <thead className="bg-gray-50/50">
              <tr>
                <th className="px-6 py-4 text-left text-[10px] font-black text-gray-400 uppercase tracking-widest">Produit</th>
                <th className="px-6 py-4 text-left text-[10px] font-black text-gray-400 uppercase tracking-widest">Catégorie</th>
                <th className="px-6 py-4 text-right text-[10px] font-black text-gray-400 uppercase tracking-widest">Prix</th>
                <th className="px-6 py-4 text-right text-[10px] font-black text-gray-400 uppercase tracking-widest">Stock</th>
                <th className="px-6 py-4 text-right text-[10px] font-black text-gray-400 uppercase tracking-widest">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-50">
              {filteredDrugs.map(drug => (
                <tr key={drug.id} className="hover:bg-gray-50/50 transition">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-pharmacy-50 text-pharmacy-600 rounded-xl"><Package size={18} /></div>
                      <div>
                        <p className="text-sm font-bold text-gray-900">{drug.name}</p>
                        <p className="text-[10px] text-gray-400 font-medium">{drug.dosage}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="px-2 py-1 bg-gray-100 text-gray-600 rounded-lg text-[10px] font-black uppercase">{drug.category}</span>
                  </td>
                  <td className="px-6 py-4 text-right text-sm font-black text-gray-800">
                    {drug.price.toLocaleString()} F
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className={`inline-flex px-3 py-1 rounded-full text-xs font-black ${drug.stock < 10 ? 'bg-red-100 text-red-600' : 'bg-green-100 text-green-600'}`}>
                      {drug.stock}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right space-x-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    {canManage && (
                      <>
                        <button onClick={() => handleOpenModal(drug)} className="p-2 text-pharmacy-600 hover:bg-pharmacy-50 rounded-lg transition"><Edit2 size={16} /></button>
                        <button onClick={() => handleDelete(drug.id)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition"><Trash2 size={16} /></button>
                      </>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-fade-in">
          <div className="bg-white rounded-[32px] shadow-2xl w-full max-w-lg overflow-hidden border border-gray-100">
            <div className="bg-pharmacy-600 p-8 text-white flex justify-between items-center relative">
               <div className="relative z-10">
                  <h3 className="text-2xl font-black uppercase tracking-tight">{editingDrug ? 'Modifier' : 'Ajouter'}</h3>
                  <p className="text-pharmacy-100 text-xs font-bold uppercase tracking-widest mt-1">Fiche Produit Officine</p>
               </div>
               <button onClick={() => setIsModalOpen(false)} className="hover:bg-white/10 p-2 rounded-2xl transition relative z-10">
                  <X size={24} />
               </button>
            </div>

            <form onSubmit={handleSave} className="p-8 space-y-5">
