import { Drug, Sale, Supplier, Insurance } from '../types';
import { INITIAL_DRUGS, INITIAL_SUPPLIERS, INITIAL_INSURANCES } from '../constants';

/** 
 * API Service for managing communication with the backend.
 * Provides fallback to initial data if the backend is unavailable.
 */
export const apiService = {
    // Fetch all drugs
    getDrugs: async (): Promise<Drug[]> => {
        const saved = localStorage.getItem('fp_drugs');
        return saved ? JSON.parse(saved) : INITIAL_DRUGS;
    },

    // Fetch all sales
    getSales: async (): Promise<Sale[]> => {
        const saved = localStorage.getItem('fp_sales');
        return saved ? JSON.parse(saved) : [];
    },

    // Fetch all suppliers
    getSuppliers: async (): Promise<Supplier[]> => {
        const saved = localStorage.getItem('fp_suppliers');
        return saved ? JSON.parse(saved) : INITIAL_SUPPLIERS;
    },

    // Fetch all insurances
    getInsurances: async (): Promise<Insurance[]> => {
        const saved = localStorage.getItem('fp_insurances');
        return saved ? JSON.parse(saved) : INITIAL_INSURANCES;
    },

    // Create a new sale
    createSale: async (sale: Sale): Promise<Sale> => {
        // In a real app, this would be a POST request to Laravel
        const savedSales = await apiService.getSales();
        const updatedSales = [sale, ...savedSales];
        localStorage.setItem('fp_sales', JSON.stringify(updatedSales));
        return sale;
    }
};

import { Drug, Sale, User, Supplier, Insurance, Pharmacy } from '../types';
import { INITIAL_DRUGS, INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_INSURANCES, INITIAL_PHARMACIES } from '../constants';

class DatabaseService {
  private storageKey = 'fasopharm_cloud_db';

  constructor() {
    this.init();
  }

  private init() {
    if (!localStorage.getItem(this.storageKey)) {
      const initialDB = {
        drugs: INITIAL_DRUGS,
        sales: [],
        suppliers: INITIAL_SUPPLIERS,
        insurances: INITIAL_INSURANCES,
        users: INITIAL_USERS,
        pharmacies: INITIAL_PHARMACIES,
        logs: []
      };
      localStorage.setItem(this.storageKey, JSON.stringify(initialDB));
    }
  }

  private getDB() {
    return JSON.parse(localStorage.getItem(this.storageKey) || '{}');
  }

  private saveDB(db: any) {
    localStorage.setItem(this.storageKey, JSON.stringify(db));
  }

  // --- API DRUGS ---
  async getDrugs(pharmacyId?: string): Promise<Drug[]> {
    const db = this.getDB();
    if (!pharmacyId) return db.drugs;
    return db.drugs.filter((d: Drug) => d.pharmacyId === pharmacyId);
  }

  async saveDrug(drug: Partial<Drug>, userId: string): Promise<Drug> {
    const db = this.getDB();
    const id = drug.id || `drug_${Date.now()}`;
    const newDrug = { ...drug, id } as Drug;

    const index = db.drugs.findIndex((d: Drug) => d.id === id);
    if (index > -1) db.drugs[index] = newDrug;
    else db.drugs.push(newDrug);

    this.logAction(userId, 'SAVE_DRUG', `Produit ${newDrug.name} mis à jour/créé`);
    this.saveDB(db);
    return newDrug;
  }

  // --- API SALES ---
  async createSale(sale: Sale, userId: string): Promise<Sale> {
    const db = this.getDB();
    db.sales.push(sale);

    // Décrémenter le stock
    sale.items.forEach(item => {
      const drug = db.drugs.find((d: Drug) => d.id === item.id);
      if (drug) drug.stock -= item.quantity;
    });

    this.logAction(userId, 'CREATE_SALE', `Vente ${sale.id} enregistrée (${sale.total} F)`);
    this.saveDB(db);
    return sale;
  }

  async getSales(pharmacyId?: string): Promise<Sale[]> {
    const db = this.getDB();
    if (!pharmacyId) return db.sales;
    return db.sales.filter((s: Sale) => s.pharmacyId === pharmacyId);
  }

  // --- API INFRA ---
  async getSuppliers(pharmacyId: string): Promise<Supplier[]> {
    return this.getDB().suppliers.filter((s: Supplier) => s.pharmacyId === pharmacyId);
  }

  async getInsurances(pharmacyId: string): Promise<Insurance[]> {
    return this.getDB().insurances.filter((i: Insurance) => i.pharmacyId === pharmacyId);
  }

  // --- LOGGING & AUDIT ---
  private logAction(userId: string, action: string, details: string) {
    const db = this.getDB();
    db.logs.unshift({
      id: `log_${Date.now()}`,
      userId,
      action,
      details,
      timestamp: new Date().toISOString()
    });
    // Garder seulement les 100 derniers logs
    db.logs = db.logs.slice(0, 100);
    this.saveDB(db);
  }

  async getAuditLogs() {
    return this.getDB().logs || [];
  }
}

export const dbService = new DatabaseService();

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Analyse les tendances de vente pour suggérer des optimisations de stock
 */
export const getBusinessIntelligence = async (salesContext: string, drugsContext: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyse ces données de vente : ${salesContext} et ce stock : ${drugsContext}. 
      Identifie les 3 médicaments les plus vendus et ceux qui risquent une rupture. 
      Retourne un résumé exécutif court pour le pharmacien.`,
    });
    return response.text;
  } catch (error) {
    console.error("BI Error:", error);
    return "Analyse indisponible.";
  }
};

